import java.util.ArrayList;import java.util.List;import java.util.Map;
final class TimeoutPattern{static final class FakeClock{int now;void advance(int value){now+=value;}}@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){FakeClock clock=new FakeClock();int deadline=((Number)input.get("deadline_ms")).intValue();List<Map<String,Object>>out=new ArrayList<>();for(Map<String,Object>op:(List<Map<String,Object>>)input.getOrDefault("operations",List.of())){int duration=((Number)op.get("duration_ms")).intValue();if(clock.now+duration<=deadline){clock.advance(duration);out.add(Map.of("name",op.get("name"),"status","completed","outcome","success"));}else{clock.advance(Math.max(0,deadline-clock.now));out.add(Map.of("name",op.get("name"),"status","timed_out","outcome",Boolean.TRUE.equals(op.get("side_effecting"))?"unknown":"abandoned"));break;}}return Map.of("outcomes",out,"now_ms",clock.now);}}
